def route(path):
  print(f'Registering {path}')
  def decorator(func):
    print('Decorator attached')
    def wrapper(*args, **kwargs):
      print('Handling request')
      return func(*args, **kwargs)
    return wrapper
  return decorator

@route('/home')
def home_view():
  return 'Welcome'

print('App started')
